var e=JSON.parse(`[{"id":"L2_1","type":"subtitle","speaker":null,"text":{"KOREA":"관리국 직할 도시 <color=#ffd34c>그라운드 원</color>\\n관리국 카운터 아카데미","JPN":"管理局直轄都市<color=#ffd34c>グラウンド・ワン</color>\\n管理局カウンターアカデミー","ENG":"Administration Direct Control City, <color=#ffd34c>Ground One</color>\\nAdministration Counter Academy","TWN":"管理局直轄市<color=#ffd34c>G1</color>\\n制裁者學院"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"subtitle","speaker":null,"text":{"KOREA":"<color=#ffd34c>관리국 최고 등급 재난 경보</color>\\n3시간 전","JPN":"<color=#ffd34c>管理局最高ランクの災難警報</color>\\n3時間前","ENG":"<color=#ffd34c>Highest-Level Disaster Alert</color>\\n3 Hours Earlier","TWN":"<color=#ffd34c>管理局最高級別災難警報</color>\\n3小時前"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"아아~ 다들 잘 들리나~?","JPN":"ああ～みんな聞こえとる～？","ENG":"Ah, ah. Can everyone hear me fine?","TWN":"喂喂～大家有聽到嗎～?"},"stage":{"bg":"CLASS","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L7_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"갑작스럽지만 잘 있어거라, 얘들아~","JPN":"急やけど、ちょっと行ってくるわ～","ENG":"This is sudden, but farewell for now, kiddos!","TWN":"雖然有些突然，不過再會囉～"},"stage":{"bg":"CLASS","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"이 미리네 쌤은 이 세상 온갖 굴레랑 속박을 훌훌 벗어뿌고.","JPN":"このマリ先生はあらゆる束縛から解き放たれて……","ENG":"Ms. Mi Rinae is casting off every shackle and burden in this world.","TWN":"你們宓璃奈老師，要把世上的一切束縛全都甩開，"},"stage":{"bg":"CLASS","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"행복을 찾으러 간데이~","JPN":"幸せを探しに行くで～","ENG":"She's off to find happiness!","TWN":"去尋找自己的幸福啦～　"},"stage":{"bg":"CLASS","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"그러니 내 돌아올 때까지 조용히 자습하고 있거라~","JPN":"せやから、ウチが帰ってくるまでおとなしく自習して待っとるんやで～","ENG":"So till I come back, keep quiet and self-study, okay?","TWN":"所以在我回來之前，乖乖地自習吧～"},"stage":{"bg":"CLASS","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"으으! 이 낙하산 선생이 진짜……!","JPN":"うう！！　あのコネ教師……！","ENG":"Ugh! That parachute teacher's at it again...!","TWN":"呃呃！你這個空降部隊真是……！"},"stage":{"bg":"CLASS","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"오늘 수행 능력 평가한다고 해서, 기껏 준비해 왔더니… 자습이나 하라고!?","JPN":"今日はテストがあるって言うからせっかく準備してきたのに……自習ですって？","ENG":"I came all prepared because today was supposed to be a performance test... and now she just says self-study?!","TWN":"今天說好要進行能力評估，我準備得那麼認真……結果你現在說要自習！？"},"stage":{"bg":"CLASS","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"나이엘, 너 그러면서 은근히 미리네 선생님 수업은 열심히 듣더라?","JPN":"でもナイエルって意外とマリ先生の授業はちゃんと聞いてるよね。","ENG":"Naielle, funny you say that. Don't you always take Ms. Mi Rinae's classes seriously?","TWN":"奈爾，你說是這樣說，但其實很認真在聽宓璃奈老師的課欸？"},"stage":{"bg":"CLASS","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L17_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"맨날 티격태격하지만, 생각보다 사이 좋은 거 아니야?","JPN":"なんだかんだ言って、結構仲良しなんじゃないの？","ENG":"You bicker all the time, but maybe you're actually closer than you let on?","TWN":"雖然總是吵吵鬧鬧的，但關係比想像中要好的樣子？"},"stage":{"bg":"CLASS","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L18_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"소인도 그렇게 생각하오.","JPN":"自分も同意見です。","ENG":"I would think so as well.","TWN":"在下也這麼認為。"},"stage":{"bg":"CLASS","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L19_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"교학상장하며, 함께 성장한다면 훌륭한 사제지간이라고 할 수 있소.","JPN":"教学相長。共に成長していければ実に素晴らしい師弟関係といえるでしょう。","ENG":"If teacher and pupil grow together through mutual learning, that is a fine bond indeed.","TWN":"教學相長，共同成長，這才是良好的師生關係。"},"stage":{"bg":"CLASS","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"으악, 시끄러워! 훌륭한 사제지간은 개뿔이!","JPN":"うるさい！　何が素晴らしい師弟関係よ！","ENG":"Ugh, shut it! Fine bond my foot!","TWN":"很吵欸你們！什麼狗屁師徒關係！"},"stage":{"bg":"CLASS","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"기간제라고 하더니, 아예 눌러앉아 버려가지곤……!","JPN":"期間限定って言ってたくせに、完全に居座っちゃって……！","ENG":"She was supposed to be temporary, but she just stayed and stayed...!","TWN":"說是約聘的，結果現在乾脆賴著不走……！"},"stage":{"bg":"CLASS","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"대체 언제 그만두는 거야, 그 인간?","JPN":"いったいいつ辞めるつもりなのよ、あの人！","ENG":"When is she ever going to quit?","TWN":"那個人到底什麼時候要走？"},"stage":{"bg":"CLASS","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"PRESIDENT_PROMISE_NULL_NPC","text":{"KOREA":"……이제 가는 거야, 리네야?","JPN":"……マリちゃん、もう行くの？","ENG":"...So you're leaving now, Rinae?","TWN":"……你要走了嗎，宓璃奈？"},"stage":{"bg":"CIRCLEROOM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_PROMISE_NULL_NPC","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L29_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"응, 쌤이 도와달라 캤으니까, 이제 가야지.","JPN":"うん。先生が手ぇ貸してくれ言うから行かなあかん。","ENG":"Yeah. Teach asked me to help, so I've gotta go.","TWN":"嗯，是老師請我幫的忙，當然要去。"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_MOVEMENT_04"},{"id":"L30_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"그동안 신세 참 많이 졌다. 애들이랑 이제 막 정 붙었는데, 아쉽데이.","JPN":"今まで世話になったな。やっとみんなと仲良くなれたのに残念やなぁ。","ENG":"I really leaned on you. And I just started to bond with the kids, so that's a shame.","TWN":"這段時間真多謝你的關照囉。剛和孩子們建立起感情就要離開，有點遺憾呢。"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"PRESIDENT_PROMISE_NULL_NPC","text":{"KOREA":"나이엘이 서운해할 거야. 그리고 다른 아이들도.","JPN":"ナイエルが寂しがるわ。他の子たちも。","ENG":"Naielle will miss you. The others too.","TWN":"奈爾會難過的，還有其他孩子們也是。"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_PROMISE_NULL_NPC","face":"UNIT_HATE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"PRESIDENT_PROMISE_NULL_NPC","text":{"KOREA":"언제든 돌아와도 괜찮아. 우리도 여기서 널 기다리고 있을 테니까.","JPN":"いつでも帰って来ていいからね。私たちもここであなたを待っているから。","ENG":"Come back anytime. We'll be waiting here for you.","TWN":"你隨時都可以回來。我們也會在這裡等著你。"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_PROMISE_NULL_NPC","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"가스나, 너무 걱정하지 마라. 내 뭐, 죽으러 가는 것도 아니고~","JPN":"まったく、そない心配せんでええって。別に死地に向かうわけやないしな。","ENG":"Girl, don't worry so much. It's not like I'm going off to die!","TWN":"放心唄，我又不是去送死～"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"PRESIDENT_PROMISE_NULL_NPC","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_PROMISE_NULL_NPC","face":"UNIT_HATE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"PRESIDENT_PROMISE_NULL_NPC","text":{"KOREA":"그렇지만 리네야…….","JPN":"でも、マリちゃん……","ENG":"But Rinae...","TWN":"不過宓璃奈……"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_PROMISE_NULL_NPC","face":"UNIT_HATE"},"C":null,"R":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L38_1","type":"dialog","speaker":"PRESIDENT_PROMISE_NULL_NPC","text":{"KOREA":"너도 알고 있잖아. 이제 우리들의 시대는 지나가 버렸다는 걸…….","JPN":"分かってると思うけど、もう私たちの時代は終わったのよ……","ENG":"You know as well as I do. Our time has passed...","TWN":"你也知道的，我們的時代已經過去了……"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_PROMISE_NULL_NPC","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L41_1","type":"dialog","speaker":"PRESIDENT_PROMISE_NULL_NPC","text":{"KOREA":"20여 년 전, 그 날의 관리 실패 이후…….","JPN":"20年くらい前の、あの日の管理失敗の後……","ENG":"Since the Administration Failure twenty years ago...","TWN":"20多年前，自從那天的管理失敗之後……"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"THEMA_GAMECIRCLE_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L42_1","type":"dialog","speaker":"PRESIDENT_PROMISE_NULL_NPC","text":{"KOREA":"시공간 동결 조치로 목숨은 건졌지만, 우린 여전히 후유증으로부터 자유롭지 못해.","JPN":"時空間凍結措置で命は助かったものの、私たちはいまだに後遺症に悩まされているわ。","ENG":"We survived due the temporal suspension, but none of us escaped the aftereffects.","TWN":"雖然透過時空凍結措施保住了性命，但我們仍然無法擺脫後遺症。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"THEMA_GAMECIRCLE_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L43_1","type":"dialog","speaker":"PRESIDENT_PROMISE_NULL_NPC","text":{"KOREA":"모르긴 몰라도, 현장을 가장 앞장서던 너는 우리보다 훨씬 상태가 안 좋겠지.","JPN":"おそらく、誰よりも現場を駆け巡っていたあなたは、私たちよりずっとひどいはずよ。","ENG":"And you, who stood at the front, must be in worse shape than any of us.","TWN":"雖說不太清楚，但總是衝在最前線的你，狀態一定比我們更差吧。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"THEMA_GAMECIRCLE_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L44_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"THEMA_GAMECIRCLE_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L48_1","type":"dialog","speaker":"PRESIDENT_PROMISE_NULL_NPC","text":{"KOREA":"우리가 다시 눈을 뜨던 날, 약속 기억해?","JPN":"再び目を覚ました日に交わした約束、覚えている？","ENG":"Remember the promise when we awoke?","TWN":"我們再次睜開眼的那天，你還記得我們的約定嗎？"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_PROMISE_NULL_NPC","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L49_1","type":"dialog","speaker":"PRESIDENT_PROMISE_NULL_NPC","text":{"KOREA":"앞으로의 일은, 앞으로를 살아갈 이들에게 맡기고, 우리는 우리의 남은 삶을 살자고.","JPN":"未来のことは、未来を生きる人たちに任せて、私たちは私たちの人生を生きようっていう約束。","ENG":"That the future belonged to those who would live it, while we lived out what's left of ours.","TWN":"未來的事情，就交給未來的人去處理，我們就過好自己的餘生吧。"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_PROMISE_NULL_NPC","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L50_1","type":"dialog","speaker":"PRESIDENT_PROMISE_NULL_NPC","text":{"KOREA":"그래서 보라는 과거를. 우리의 추억을 간직하기 위해, 게임을 만들기로 했고.","JPN":"だからシホちゃんは過去を……私たちの思い出を形にするためにゲームを作ることにして。","ENG":"So Bora cherished the past, making games to preserve our memories.","TWN":"寶拉是為了過去，為了保存我們的回憶，所以決定製作遊戲。"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_PROMISE_NULL_NPC","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L1_1","type":"dialog","speaker":"PRESIDENT_PROMISE_NULL_NPC","text":{"KOREA":"나는 미래를. 선생님처럼 내일을 살아갈 아이들을 위해 선생님이 되었어.","JPN":"私は未来を……先生みたいに、明日を生きていく子どもたちのために教師になったわ。","ENG":"And I devoted myself to tomorrow, becoming a teacher for the children who'd live it.","TWN":"我是為了未來，像老師一樣為了生活在明天的孩子們，所以成為老師。"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_PROMISE_NULL_NPC","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L3_1","type":"dialog","speaker":"PRESIDENT_PROMISE_NULL_NPC","text":{"KOREA":"나는 너도 너에게 주어진 <color=#ffd34c>오늘</color>을 살아야 한다고 생각해.","JPN":"私はね、マリちゃんにも、今この瞬間に与えられた<color=#ffd34c>今日</color>を生きてほしいの。","ENG":"I think you too should live for your <color=#ffd34c>today</color>.","TWN":"我認為你也應該活在屬於你的<color=#ffd34c>今天</color>。"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_PROMISE_NULL_NPC","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"다인아, 내는…….","JPN":"タエ、ウチは……","ENG":"Dain, I–","TWN":"妲茵，我……"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"PRESIDENT_PROMISE_NULL_NPC","text":{"KOREA":"이제 우리는 학생이 아니야. 그렇다고 관리국 현역 요원도 아니지.","JPN":"もう私たちは学生じゃないわ。管理局の現役要員でもない。","ENG":"We're no longer students. Nor active agents.","TWN":"我們已經不是學生了，也不是管理局的現役人員。"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_PROMISE_NULL_NPC","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"PRESIDENT_PROMISE_NULL_NPC","text":{"KOREA":"우리들의 시대는 이미 지나가 버렸어. 반드시 네가 나서야 할 이유는 없어.","JPN":"私たちの時代はもう終わったのよ。あなたが出る必要はないわ。","ENG":"Our era has passed. You have no obligation to step in.","TWN":"我們的時代過去了，你沒有必要一定要出面。"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_PROMISE_NULL_NPC","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"PRESIDENT_PROMISE_NULL_NPC","text":{"KOREA":"같이 선생님께 부탁드려보자. 선생님께서는 분명…….","JPN":"一緒に、先生に頼んでみましょう。先生ならきっと……","ENG":"Let's ask Teacher together. He'll surely–","TWN":"我們一起拜託老師吧，老師一定會……"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_PROMISE_NULL_NPC","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"아하하, 이거 쪼매 부끄럽네.","JPN":"あはは、こりゃ照れくさいな。","ENG":"Ahaha, this is kinda embarrassing.","TWN":"啊哈哈，這有點不好意思呢。"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_PROMISE_NULL_NPC","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L11_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"니가 날 이렇게까지 걱정해 줄지는 몰랐는데?","JPN":"あんたがここまでウチのこと心配してくれるとは思わんかったわ。","ENG":"Didn't think you'd worry about me this much.","TWN":"沒想到你這麼擔心我。"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_PROMISE_NULL_NPC","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"근데 나는 괘안타, 다인아.","JPN":"でもウチは大丈夫やで、タエ。","ENG":"But I'm all right, Dain.","TWN":"不過我沒事的，妲茵。"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"뭣보다도, 우리가 늘 믿고 따랐던 <color=#ffd34c>선생님</color>의 부탁인데.","JPN":"何より、ウチらがずっと信じて慕ってた<color=#ffd34c>先生</color>からのお願いやからな。","ENG":"More than anything, this is <color=#ffd34c>Teach</color>'s request—the one we always trusted.","TWN":"最重要的是，這是我們一直信任和追隨的<color=#ffd34c>老師</color>的請求。"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"애초에 쌤이 없었으면, 우리에게 <color=#ffd34c>오늘</color>도 없었을 거다.","JPN":"先生がいなかったら、そもそもウチらに<color=#ffd34c>今日</color>いう日もなかったはずや。","ENG":"If not for him, we wouldn't even have this <color=#ffd34c>today</color>.","TWN":"要不是老師，我們也沒有所謂的<color=#ffd34c>今天</color>。"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"그 쌤이 도와달라카는데, <color=#ffd34c>우리</color>가 가만있을 수 있나?","JPN":"その先生に頼まれてんのに、<color=#ffd34c>ウチら</color>が何もせんわけにはいかへんやろ？","ENG":"With him asking, how can <color=#ffd34c>we</color> just sit back?","TWN":"既然是老師的請求，<color=#ffd34c>我們</color>能袖手旁觀嗎？"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"PRESIDENT_PROMISE_NULL_NPC","text":{"KOREA":"그건 그렇지만…….","JPN":"それはそうだけど……","ENG":"Still...","TWN":"話是沒錯……"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_PROMISE_NULL_NPC","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"으응! 마, 됐다. 됐어. 내도 이제 어른 아이가~","JPN":"うん、うん！　わかっとるって。もうウチも立派な大人や。","ENG":"Nope, enough. I'm grown up now!","TWN":"嗯嗯！好了，好了。我現在也是大人了～"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_PROMISE_NULL_NPC","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L21_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"그리고 나 아직 현역 시절 실력, 하나도 안 죽었거든?","JPN":"それにな、まだ現役時代の腕は鈍ってへんし！","ENG":"My old skills haven't dulled one bit!","TWN":"而且我現在還是寶刀未老喔？"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_PROMISE_NULL_NPC","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"침식체 같은 거, 이래이래 슉슉 해서 팍~! 하면 원펀치로……","JPN":"侵食体なんか、パパーッとワンパンで……","ENG":"C.O.s? Swish, swish, and BLAM! Down in one pun–","TWN":"像侵蝕體這種東西，這樣這樣唰唰，然後啪～！一拳就……"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_COMBAT_ALL_MOVEMENT_05"},{"id":"L24_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"앗!","JPN":"うわっ！","ENG":"Ah!","TWN":"啊！"},"stage":{"bg":"BLACK","bgm":"THEMA_GAMECIRCLE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_COMBAT_ALL_BONE_CRACK"},{"id":"L27_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"아야야! 허리 삐끗해뿟네.","JPN":"いてて～腰抜けた～","ENG":"Ow, my back's gone out again.","TWN":"啊呀呀！扭到腰了。"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L28_1","type":"dialog","speaker":"PRESIDENT_PROMISE_NULL_NPC","text":{"KOREA":"리, 리네야…? 괜찮아……!?","JPN":"マ、マリちゃん……？　大丈夫……！？","ENG":"R-Rinae...? Are you okay...?!","TWN":"宓，宓璃奈……？你沒事吧……！？"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_PROMISE_NULL_NPC","face":"UNIT_SURPRISE"},"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L29_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"호라! 모 젠젠 멀쩡하자나?","JPN":"ほら！　もう全然平気やし！","ENG":"See? Totally fine.","TWN":"看吧！完全沒事！"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_PROMISE_NULL_NPC","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_PRIDE"}}},"sfx":"FX_CUTSCEN_TADA"},{"id":"L30_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"아하하! 니 바보가? 장난이다, 장난!","JPN":"あはは！　あんたチョロすぎやな！　冗談や、冗談！","ENG":"Ahaha, fooled you. Just kidding!","TWN":"啊哈哈！你這傻瓜！我開玩笑的啦！"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_PROMISE_NULL_NPC","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L31_1","type":"dialog","speaker":"PRESIDENT_PROMISE_NULL_NPC","text":{"KOREA":"푸흡……!","JPN":"ぷふっ……！","ENG":"Pfft...!","TWN":"噗哧……！"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_PROMISE_NULL_NPC","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L33_1","type":"dialog","speaker":"PRESIDENT_PROMISE_NULL_NPC","text":{"KOREA":"아하하하하하하하…! 그게 대체 언제 적 말장난이야!","JPN":"あははははは……！　あなたって本当……！","ENG":"Ahahaha...! That's such an old joke!","TWN":"啊哈哈哈哈哈哈哈……！好老派的玩笑！"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_PROMISE_NULL_NPC","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L34_1","type":"dialog","speaker":"PRESIDENT_PROMISE_NULL_NPC","text":{"KOREA":"하여간 리네는 옛날이랑 하나도 안 변했다니까.","JPN":"マリちゃんは昔と全然変わってないわね。","ENG":"You haven't changed a bit, Rinae.","TWN":"總之，你和以前一樣一點都沒變。"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_PROMISE_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"으음? 근데 보라 갸는 어데 갔노?","JPN":"あれ？　そういやシホはどこ行ったん？","ENG":"Hmm? Where's Bora anyway?","TWN":"嗯？不過寶拉那傢伙去哪了？"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_PROMISE_NULL_NPC","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L38_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"가스나, 회사 일 때문에 바쁘다 바쁘다 하더니, 진짜 빠쁜갑다.","JPN":"あいつ、いつも忙しい、忙しい言うてたけど、会社の仕事ホンマに忙しいみたいやな。","ENG":"Always saying she's swamped with work, guess she really is.","TWN":"她老說公司忙，看來是真的很忙咧。"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_PROMISE_NULL_NPC","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L39_1","type":"dialog","speaker":"PRESIDENT_PROMISE_NULL_NPC","text":{"KOREA":"아, 보라는 말이지……","JPN":"あ、シホちゃんはね……","ENG":"Ah, about Bora...","TWN":"那個，寶拉她……"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_PROMISE_NULL_NPC","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L41_1","type":"dialog","speaker":"VIOLET_LEGACY_NULL_NPC","text":{"KOREA":"……안 늦었지? 아직?","JPN":"……間に合った？","ENG":"...I'm not too late, am I?","TWN":"……來得及吧？還沒走吧？"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"가스나! 쪼매만 더 늦었으면, 얼굴도 못 볼 뻔했 안하나?","JPN":"こら！　もうちょい遅かったら、顔も見んと行かなあかんところやったで！","ENG":"Girl! Any later and I'd have missed your face!","TWN":"寶拉！再晚一點我就見不到你咧。"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_PROMISE_NULL_NPC","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L45_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"그래서? 와 늦었는데?","JPN":"で、どないしたん？","ENG":"So? Why late?","TWN":"所以咧？你為啥這麼晚來？"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_PROMISE_NULL_NPC","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L47_1","type":"dialog","speaker":"VIOLET_LEGACY_NULL_NPC","text":{"KOREA":"미안… 줄 게 있었거든. 리네한테.","JPN":"ごめん……渡したいものがあったから、マリに。","ENG":"Sorry... I had something to give you.","TWN":"對不起…有東西要給你。"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"VIOLET_LEGACY_NULL_NPC","text":{"KOREA":"응…. 어차피 말려도 갈 거잖아. 리네라면…….","JPN":"どうせ……止めても行くんでしょう、マリは……","ENG":"Well... I knew you'd go, no matter what. That's you, Rinae...","TWN":"嗯…反正阻止你，也沒用……"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"아하하, 니는 확실히 날 잘 아네.","JPN":"あはは、よう分かってるな。","ENG":"Ahaha, you know me well.","TWN":"啊哈哈，你確實很瞭解我。"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_PROMISE_NULL_NPC","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L3_1","type":"dialog","speaker":"VIOLET_LEGACY_NULL_NPC","text":{"KOREA":"그러니까… 하는 거야. 나도 내 역할…….","JPN":"だから……果たす。私も、自分の役目……","ENG":"That's why... I'm doing this. My role...","TWN":"所以……我也要扮演好角色……"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"VIOLET_LEGACY_NULL_NPC","text":{"KOREA":"서포트, <color=#ffd34c>옛날</color>처럼.","JPN":"サポート。<color=#ffd34c>昔</color>みたいに。","ENG":"Support, just like the <color=#ffd34c>old days</color>.","TWN":"我要支援你，跟<color=#ffd34c>以前</color>一樣。"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"이건……?","JPN":"これは……？","ENG":"This is...?","TWN":"這是……？"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_PROMISE_NULL_NPC","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L10_1","type":"dialog","speaker":"VIOLET_LEGACY_NULL_NPC","text":{"KOREA":"<color=#ffd34c>레거시 큐브</color>. 판도라 사의 프로토타입 증강현실 구현장치.","JPN":"<color=#ffd34c>レガシー・キューブ</color>。パンドラ社のプロトタイプ拡張現実具現装置。","ENG":"A <color=#ffd34c>Legacy Cube</color>. Pandora's prototype AR implementation device.","TWN":"<color=#ffd34c>傳承魔方</color>。是潘朵拉公司的原型擴增現實具現化裝置。"},"stage":{"bg":"LEGACY_GROUND","bgm":"THEMA_GAMECIRCLE_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"VIOLET_LEGACY_NULL_NPC","text":{"KOREA":"관리국 증강현실 기술과 카운터즈 레거시에서 코어로 사용했던 오버로드…….","JPN":"管理局の拡張現実技術と、カウンターズ・レガシーでコアとして使ったオーバーロード……","ENG":"Combined Administration's AR tech with the Overlord core from Counters Legacy...","TWN":"將管理局的擴增現實技術和制裁者的遺產中作為核心使用的超載……"},"stage":{"bg":"LEGACY_GROUND","bgm":"THEMA_GAMECIRCLE_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"VIOLET_LEGACY_NULL_NPC","text":{"KOREA":"접목했어. 두 기술을…. 나랑, 가람이 함께…….","JPN":"組み合わせた。2つの技術……私と、ヒカリで……","ENG":"Garam and I worked on it together...","TWN":"我和嘉蘭一起把兩種技術相結合……"},"stage":{"bg":"LEGACY_GROUND","bgm":"THEMA_GAMECIRCLE_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"그 가람 씨가……? 그거 대단한데……!","JPN":"あのヒカリさんが……？　すごいやん……！","ENG":"Garam too...? That's amazing...!","TWN":"那個嘉蘭……？真厲害……！"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_PROMISE_NULL_NPC","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"VIOLET_LEGACY_NULL_NPC","text":{"KOREA":"이 큐브가 있다면…….","JPN":"このキューブがあれば……","ENG":"With this cube...","TWN":"有這個魔方的話……"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"VIOLET_LEGACY_NULL_NPC","text":{"KOREA":"카운터즈 레거시 서버에서, 그때그때 현실로 불러올 수 있어.","JPN":"カウンターズ・レガシーのサーバーから、随時現実に呼び出せる。","ENG":"We can call out equipment from the Counters Legacy server, in real time.","TWN":"可以在制裁者的遺產伺服器中隨時召喚到現世中。"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"VIOLET_LEGACY_NULL_NPC","text":{"KOREA":"<color=#ffd34c>게임</color> 속의 장비를.","JPN":"<color=#ffd34c>ゲーム</color>の中の装備。","ENG":"Items from the <color=#ffd34c>game</color>.","TWN":"就是<color=#ffd34c>遊戲</color>裡的裝備。"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"아핫! 그거 카운터즈 사가 설정 아이가! 옛날 생각 팍 나는데?","JPN":"あははっ！　それカウンターズ・サーガの設定やないか！　昔のこと思い出すなぁ～","ENG":"Ahaha! That's straight outta Counters Saga! Brings back memories.","TWN":"啊哈！那是制裁者的遺產的設定唄！讓我想起了過去的日子呢？"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_PROMISE_NULL_NPC","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L24_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"바이올렛! 무기를 전송해도~!","JPN":"バイオレット！　武器を転送して！","ENG":"Violet! Send me a weapon!","TWN":"寶拉！幫我換武器唄！"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_PROMISE_NULL_NPC","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"게임 속 설정을 진짜로 해낼 줄이야. 세월 참 많이 바꼈다, 안 그라나?","JPN":"ゲームの設定を現実にできるなんて、ええ時代になったな。","ENG":"To think you actually pulled off that game feature. Times have changed.","TWN":"沒想到你真的能把遊戲中的設置在現世中實現。時間真的帶來許多改變呢，不是嗎？"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_PROMISE_NULL_NPC","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L27_1","type":"dialog","speaker":"VIOLET_LEGACY_NULL_NPC","text":{"KOREA":"프로토타입이야. 아직은.","JPN":"プロトタイプだよ、まだ。","ENG":"It's just a prototype. For now.","TWN":"這還只是個原型。"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"VIOLET_LEGACY_NULL_NPC","text":{"KOREA":"하지만 네 물질 강화 능력이라면, 구현된 장비의 내구도를 보완할 수 있을 거야.","JPN":"でも、マリの物質強化能力で、具現した装備の耐久性を補完できる。","ENG":"But with your material-enhancement powers, you can reinforce the durability.","TWN":"但是憑藉你的物質強化能力，可以彌補裝備的耐久度。"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"하하, 그거 재밌겠는데? 고맙다, 보라야.","JPN":"へえ、面白そうやな。ありがとな、シホ。","ENG":"Haha, sounds fun. Thanks, Bora.","TWN":"哈哈，那聽起來很有趣咧？謝謝你，寶拉。"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_PROMISE_NULL_NPC","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L33_1","type":"dialog","speaker":"VIOLET_LEGACY_NULL_NPC","text":{"KOREA":"사실은, 나도 동의해. 다인이의 생각.","JPN":"正直、私も同意見だよ。タエと。","ENG":"Truth is, I agree with Dain.","TWN":"其實，我和妲茵的想法一樣。"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"VIOLET_LEGACY_NULL_NPC","text":{"KOREA":"우리들의 시대는 이미 지나가 버렸어. 그건 사실이야.","JPN":"私たちの時代は終わった。それは事実。","ENG":"Our era's already passed. That's fact.","TWN":"我們的時代已經過去了，這無法否認。"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"VIOLET_LEGACY_NULL_NPC","text":{"KOREA":"큐브가 있어도… 힘들지도 몰라. 전성기때 처럼은.","JPN":"キューブがあっても……うまくいかないかもしれない。全盛期のようには。","ENG":"Even with the cube... it won't be easy. We're not in our prime.","TWN":"即使有魔方……也很難回到全盛時期的狀態。"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"VIOLET_LEGACY_NULL_NPC","text":{"KOREA":"그러니까…….","JPN":"だから……","ENG":"So...","TWN":"所以……"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"VIOLET_LEGACY_NULL_NPC","text":{"KOREA":"그러니까 무리하지 마. 미리네.","JPN":"だから無理しないで、マリ。","ENG":"So don't push yourself, Rinae.","TWN":"所以，不要勉強自己，宓璃奈。"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"VIOLET_LEGACY_NULL_NPC","text":{"KOREA":"그리고 꼭 돌아와. 기다리고 있을 테니까.","JPN":"そして、必ず帰ってきて。待ってるから。","ENG":"And come back alive. We'll be waiting.","TWN":"一定要回來，我們會等你。"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"으아아! 이 가스나들이 진짜……!","JPN":"ああもう～！　あんたたちったら……！","ENG":"Ahhh! You girls, seriously...!","TWN":"嘖嘖！你們真是的……！"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L48_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"아까부터 왜 자꾸 사망 플래그 꽂아대노. 이래가꼬 내 살아 남겠나?","JPN":"さっきから死亡フラグ立てまくりやないか。こんなんじゃ生きて帰れへんで！","ENG":"Why keep raising death flags? How am I supposed to survive like this?","TWN":"從剛才就一副我要去赴死的樣子，這樣我還有求生慾嗎？"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"안되겠다! 이럴 때는 플래그를 역으로 써뿌는 기다!","JPN":"あかん！　こんな時は逆にフラグを利用したるで！","ENG":"Forget it! I'll flip it instead!","TWN":"不行！我要逆轉這種氛圍！"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"해치웠나? 물리쳤나? 해낸 건가? 끝난 건가? 드디어! 마침내! 이겼다, 3부 끝……!!","JPN":"やっつけたか？　倒したか？　成功したんか？　終わったんか？　やっと！　ついに！　勝った、第3部終了……！！","ENG":"Did we do it? Is it over? Did we win? Finally! At last! I win! That's it for Part 3...!!","TWN":"解決了嗎？打敗了嗎？成功了嗎？結束了嗎？終於！我贏啦！ 第三部，完！……！！"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_TADA2"},{"id":"L1_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"후우~! 이제야 속이 확 풀렸다 아이가! 이제 내 안 죽는다!!","JPN":"ふう～！　すっきりした！　これでウチの命は無事や！！","ENG":"Phew! Now the curse is broken! I won't die now!","TWN":"呼～！舒坦！我不會死哩！！"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"그라믄, 나 진짜 간다!","JPN":"ほな、ホンマに行くで！","ENG":"All right, I'm off!","TWN":"那我真的走囉！"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_COMBAT_ALL_MOVEMENT_04"},{"id":"L4_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"니들 여기서 딱 기다리고 있어라이~!","JPN":"あんたたちはここでちゃーんと待っといてな！","ENG":"Wait here for me!","TWN":"你們就在這裡等著我唄～！"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L7_1","type":"subtitle","speaker":null,"text":{"KOREA":"3시간 뒤","JPN":"3時間後","ENG":"Three hours later","TWN":"3小時後"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"subtitle","speaker":null,"text":{"KOREA":"관리국 직할 도시 <color=#ffd34c>그라운드 원</color>\\n<color=#ffd34c>A-13</color>비행장","JPN":"管理局直轄都市<color=#ffd34c>グラウンド・ワン</color>\\n<color=#ffd34c>A-13</color>飛行場","ENG":"Administration Direct Control City, <color=#ffd34c>Ground One</color>\\n<color=#ffd34c>A-13</color> Airfield","TWN":"管理局直轄市<color=#ffd34c>G1</color>\\n<color=#ffd34c>A-13</color>機場"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_NULL","text":{"KOREA":"관리국 최고 등급 재난 경보에 따른, 특별 선별 인원 확인 중…….","JPN":"管理局最高ランクの災難警報による、特別選別人員確認中……","ENG":"Confirming special dispatch personnel per highest-level disaster alert...","TWN":"根據管理局最高等級災難警報，正在確認特別選拔人員……"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L12_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_NULL","text":{"KOREA":"식별 코드 확인되었습니다.","JPN":"識別コード、確認しました。","ENG":"Identification code confirmed.","TWN":"識別代碼已確認。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_TECH"},{"id":"L13_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_NULL","text":{"KOREA":"그럼, 캄파멘토까지 모셔다 드리겠습니다. 미리네 님.","JPN":"では、カンパメントまでお送りいたします。オノデラ・マリ様。","ENG":"We'll escort you to Campamento, Ms. Rinae.","TWN":"宓璃奈，我會護送你到坎帕門托。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"이야~ 사비로 캄파멘토까지 가려고 했으면, 돈 좀 깨졌을 낀데.","JPN":"いやぁ～自腹でカンパメントまで行ったらめっちゃ金かかったやろな。","ENG":"Whew! If I'd paid my own way to Campamento, it would've cost a fortune.","TWN":"哎呀～如果是自費去坎帕門托的話肯定要花不少錢吧。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L16_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"차원 함선까지 준비해 둘 줄이야. 쌤은 역시 준비성 하나는 기가 막히네.","JPN":"次元艦船まで用意してくれるとは。さすが先生、抜かりないわ。","ENG":"Didn't think Teach would prep a dimensional ship. Always thorough.","TWN":"居然連次元艦船都準備好啦。老師果然是很周全呢。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"AURA_ADMIN_NULL_QM","text":{"KOREA":"저… 안녕하세요…….","JPN":"あの……こんにちは……","ENG":"Um... hello...","TWN":"你…你好……"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"AURA_ADMIN_NULL_QM","text":{"KOREA":"혹시 당신이 저와 이번 작전을 함께 하실 <color=#ffd34c>트레저 헌터</color>신가요?","JPN":"もしかして、あなたが今回の作戦でご一緒する<color=#ffd34c>トレジャーハンター</color>さんですか？","ENG":"Are you the <color=#ffd34c>treasure hunter</color> who'll be working with me?","TWN":"你就是要和我一起執行這次任務的<color=#ffd34c>尋寶獵人</color>嗎？"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"음? 니는 누구고?","JPN":"ん？　あんたは誰や？","ENG":"Hm? And you are?","TWN":"嗯？你是誰咧？"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"아하! 니가 쌤이 말한 <color=#ffd34c>협력자</color>가?","JPN":"あ～！　先生が言ってた<color=#ffd34c>協力者</color>か！","ENG":"A-ha! You must be the <color=#ffd34c>cooperator</color> Teach mentioned.","TWN":"啊哈！你就是老師說的<color=#ffd34c>合作夥伴</color>嗎？"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"AURA_ADMIN_NULL_QM","text":{"KOREA":"쌤이요? 쌤이 누구죠?","JPN":"先生？　先生とはどなたのことですか？","ENG":"Teach? Who's that?","TWN":"老師？老師是誰？"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"AURA_ADMIN_NULL_QM","text":{"KOREA":"종자님이 말씀하시길, 이곳에서 미리네라는 분을 만날 수 있다고 하던데요?","JPN":"従者様によると、ここでマリさんという方に会えるとのことでしたが……","ENG":"Squire told me I'd meet someone named Rinae here.","TWN":"手下說，可以在這裡見到宓璃奈？"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"쌤은 쌤이지~ 그러는 니는 쌤한테 종자가 뭐고?","JPN":"先生は先生や。そういうあんたは先生に対して従者様ってどういうことや？","ENG":"Teach is Teach. But why are you calling Teach Squire?","TWN":"老師就是老師～你叫老師手下？"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"AURA_ADMIN_NULL_QM","text":{"KOREA":"네? 그렇지만 오러 선생님께서는 관리자님을 종자라고…….","JPN":"え？　でもオーラ先生は管理者様のことを、従者って……","ENG":"What? But Ms. Aura calls the Administrator \\"Squire\\"...","TWN":"是嗎？可是奧蘿師父ㄉ都叫管理者手下的……"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"오러? 그게 뭐꼬……?","JPN":"オーラ？　なんやそりゃ？","ENG":"Aura? What's that...?","TWN":"奧蘿？那又是誰……？"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"AURA_ADMIN_NULL_QM","text":{"KOREA":"아, 아앗! 제 소개가 부족했군요.","JPN":"あ、ああっ！　申し遅れました。","ENG":"Ah! I forgot to introduce myself.","TWN":"哎呀！我還沒自我介紹呢。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AURA_ADMIN_NULL_QM","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L31_1","type":"dialog","speaker":"AURA_ADMIN_NULL_BODY","text":{"KOREA":"저는 노르드나빅 키덜링턴 출신, 로빈 피츠워터라고 합니다……!","JPN":"私はノルドナビックのキドリントン出身、ロビン・フィッツウォーターと申します……！","ENG":"I'm Robin Fitzwater, from Kidderlington, Nordnavik...!","TWN":"我是來自諾爾德萊比吉德靈頓的蘿蘋·菲茲瓦特……！"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AURA_ADMIN_NULL_BODY","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"AURA_ADMIN_NULL_BODY","text":{"KOREA":"잘 부탁드리겠습니다, 미리네 씨!","JPN":"よろしくお願いします、マリさん！","ENG":"Pleased to meet you, Ms. Mi Rinae!","TWN":"請多多關照，宓璃奈！"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AURA_ADMIN_NULL_BODY","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};